#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> sayilar;
    int sayi;
    cout << "5 sayi girin:" << endl;
    for (int i = 0; i < 5; i++) {
        cin >> sayi;
        sayilar.push_back(sayi);
    }
    int toplam = 0;
    for (int i = 0; i < sayilar.size(); i++) {
        toplam += sayilar[i];
    }
    double ortalama = (double)toplam / sayilar.size();
    cout << "Ortalama: " << ortalama << endl;
    return 0;
}

